module ALU (  
    input [31:0] A,  
    input [31:0] B,  
    input [3:0] opcode,  
    output reg [31:0] result,  
    output reg ZF  
);  
    always @(*) begin  
        case (opcode)  
            4'b0001: result = A - B;  
            4'b0010: result = A & B;  
            4'b0011: result = A | B;  
            4'b0100: result = A ^ B;  
            4'b0101: result = ~(A | B);  
            4'b0110: result = ~(A & B);  
            4'b0111: result = ~(A ^ B);  
            4'b0000: result = A + B;  
            default: result = 32'b0;  
        endcase  
        ZF = (result == 32'b0);  
    end  
endmodule

module ALU_8bit (  
    input [7:0] A,  
    input [7:0] B,  
    input [2:0] opcode,  
    output reg [7:0] result,  
    output reg carry_out  
);  
    always @(*) begin  
        case (opcode)  
            3'b001: begin // OR  
                result = A | B;  
                carry_out = 0;  
            end  
            3'b010: begin // XOR  
                result = A ^ B;  
                carry_out = 0;  
            end  
            3'b011: begin // ADD  
                {carry_out, result} = A + B;  
            end  
            3'b100: begin // SUB  
                {carry_out, result} = A - B;  
            end  
            3'b000: begin // AND  
                result = A & B;  
                carry_out = 0;  
            end  
            default: begin  
                result = 8'b00000000;  
                carry_out = 0;  
            end  
        endcase  
    end  
endmodule

