    localparam RECEIVE = 2'b10;

    always @(posedge clk) begin
        case (ctrl_signal)
            2'b01: state <= TRANSMIT;
            2'b10: state <= RECEIVE;
            2'b00: state <= IDLE;
            default: state <= IDLE; // Default to IDLE on invalid input
        endcase
    end
endmodule

