module ethernet_mac_controller(
    input clk,
    input reset,
    input start,
    input receive,
    input forward,
    output reg [1:0] current_state
);
    // State encoding
    parameter IDLE = 2'b00, LISTENING = 2'b01, LEARNING = 2'b10, FORWARDING = 2'b11;
    reg [1:0] next_state;

    // State transition logic
    always @(*) begin
        case (current_state)
            LISTENING: begin
                if (receive) next_state = LEARNING;
                else next_state = LISTENING;
            end
            LEARNING: begin
                if (forward) next_state = FORWARDING;
                else next_state = LEARNING;
            end
            FORWARDING: begin
                next_state = IDLE; // transition back to IDLE for demo purposes
            end
            IDLE: begin
                if (start) next_state = LISTENING;
                else next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end

    // State update logic
    always @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= next_state;
    end
endmodule

module pcie_fsm (
    input wire clk,
    input wire rst,
    input wire start,
    input wire ack,
    output reg [1:0] state
);
    parameter IDLE = 2'b00;
    parameter REQUEST = 2'b01;
    parameter RESPONSE = 2'b10;
    parameter RESPONSE_DELAY = 3; // Number of clock cycles to stay in RESPONSE state

    reg [1:0] next_state;
    reg [1:0] response_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            response_counter <= 0;
        end else begin
            state <= next_state;
            if (state == RESPONSE) begin
                if (response_counter < RESPONSE_DELAY)
                    response_counter <= response_counter + 1;
                else
                    response_counter <= 0; // Reset counter after delay
            end
        end
    end

    always @(*) begin
        case (state)
            REQUEST: begin
                if (ack) 
                    next_state = RESPONSE;
                else 
                    next_state = REQUEST;
            end
            RESPONSE: begin
                if (response_counter == RESPONSE_DELAY)
                    next_state = IDLE;
                else 
                    next_state = RESPONSE;
            end
            IDLE: begin
                if (start) 
                    next_state = REQUEST;
                else 
                    next_state = IDLE;
            end
            default: next_state = IDLE;
        endcase
    end
endmodule

