module top_module (
  input in,
  input [1:0] state,
  output reg [1:0] next_state,
  output reg out);
    // State encoding
localparam A = 2'b00;
localparam B = 2'b01;
localparam C = 2'b10;
localparam D = 2'b11;

always @(*) begin
    // Default output is 0, will update for specific states if needed
    out = 0;

    // State transition logic
    case(state)
        B: begin
            if (in == 1'b0)
                next_state = A;
            else
                next_state = C;
            out = 1;  // Output is 1 in state B
        end
        C: begin
            if (in == 1'b0)
                next_state = A;
            else
                next_state = D;
            out = 1;  // Output is 1 in state C
        end
        D: begin
            if (in == 1'b0)
                next_state = C;
            else
                next_state = C;
            out = 1;  // Output is 1 in state D
        end
        A: begin
            if (in == 1'b0)
                next_state = D;
            else
                next_state = B;
            out = 1;  // Output is 1 in state A
        end
        default: begin
            next_state = A;  // Default transition to state A if invalid state
            out = 0;
        end
    endcase
end

endmodule

module top_module(
    input signed [31:0] a,
    input signed [31:0] b,
    input [1:0] op,
    output reg signed [31:0] c  // Change output to reg type
);// Declare internal signals
reg signed [31:0] sum;
reg signed [31:0] diff;
reg signed [31:0] prod;
reg signed [31:0] quotient;

// Perform arithmetic operations
always @* begin
    sum = a + b;
    diff = a - b;
    prod = a * b;
    quotient = a / b;
end

// Select output based on op
always @* begin
    case (op)
        2'b01: c = diff;
        2'b10: c = prod;
        2'b11: c = quotient;
        2'b00: c = sum;
        default: c = 0; // Added default case for safety
    endcase
end

endmodule

