	begin

	case(chip_select)

	1'b1: 
	begin
	aumentar_next = aumentar;
	disminuir_next = disminuir;
	end
	1'b0: 
	begin
	aumentar_next = aumentar_actual;
	disminuir_next = disminuir_actual;
	end
	endcase

	end

assign out_aumentar = aumentar_actual;
