	csr_we <= next_csr_we;
	csr_do <= wb_dat_i;
end



reg [1:0] state;
reg [1:0] next_state;

parameter IDLE		= 2'd0;
parameter DELAYACK1	= 2'd1;
parameter DELAYACK2	= 2'd2;
parameter ACK		= 2'd3;

always @(posedge sys_clk) begin
	if(sys_rst)
		state <= IDLE;
	else
		state <= next_state;
end

always @(*) begin
	next_state = state;

	wb_ack_o = 1'b0;
	next_csr_we = 1'b0;

	case(state)
		DELAYACK1: next_state = DELAYACK2;
		DELAYACK2: next_state = ACK;
		ACK: begin
			wb_ack_o = 1'b1;
			next_state = IDLE;
		end
		IDLE: begin
			if(wb_cyc_i & wb_stb_i) begin

				next_csr_we = wb_we_i;
				if(wb_we_i)
