            B: next = in ? C : D;
            C: next = in ? A : A;
            D: next = in ? A : B;
            A: next = in ? C : C;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= A;
        else state <= next;
    end

    // Output Logic
