    reg [1:0] state, next;

    // State Transition Logic
    always @(*) begin
        case (state)
            B: next = in ? B : D;
            C: next = in ? B : B;
            D: next = in ? C : D;
            A: next = in ? D : D;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= D;
        else state <= next;
    end

    // Output Logic
    always @(*) begin
        case (state)
            A: out = 1;
            B: out = 0;
            C: out = 1;
            D: out = 1;
        endcase
    end
