    input reset,
    output reg out);// State Encoding
    parameter ON = 0, OFF = 1;
    reg [1:0] state, next;

    // State Transition Logic
    always @(*) begin
        case (state)
            OFF: next = y ? ON : OFF;
            ON: next = x ? OFF : ON;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= ON;
        else state <= next;
    end

    // Output Logic
    always @(*) begin
        case (state)
            ON: out = 0;
            OFF: out = 1;
        endcase
    end
