localparam B = 2'b01;
localparam C = 2'b10;
localparam D = 2'b11;

always @(*) begin
    // Default output is 0, will update for specific states if needed
    out = 0;

    // State transition logic
    case(state)
        B: begin
            if (in == 1'b0)
                next_state = D;
            else
                next_state = C;
            out = 1;  // Output is 1 in state B
        end
        C: begin
            if (in == 1'b0)
                next_state = C;
            else
                next_state = A;
            out = 0;  // Output is 0 in state C
        end
        D: begin
            if (in == 1'b0)
                next_state = D;
            else
                next_state = C;
            out = 1;  // Output is 1 in state D
        end
        A: begin
            if (in == 1'b0)
                next_state = D;
            else
                next_state = B;
            out = 1;  // Output is 1 in state A
        end
        default: begin
            next_state = A;  // Default transition to state A if invalid state
            out = 0;
        end
    endcase
end

endmodule

