always@(opA or opB or op )
    case(op)
        2'b01:
            logic_result=opA|opB;
        2'b10:
            logic_result=opA^opB;
        2'b11:
            logic_result=~(opA|opB);
        2'b00:
            logic_result=opA&opB;
    endcase

assign result=logic_result;


endmodule

