    always @(*) begin
        case (state)
            B: next = in ? C : A;
            C: next = in ? D : D;
            D: next = in ? C : C;
            A: next = in ? D : A;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) state <= D;
        else state <= next;
    end

    // Output Logic
    always @(*) begin
        case (state)
            A: out = 0;
            B: out = 1;
            C: out = 1;
            D: out = 1;
        endcase
    end
