    case (sel)
        3'b001: mux_out = data1;
        3'b010: mux_out = data2;
        3'b011: mux_out = data3;
        3'b100: mux_out = data4;
        3'b101: mux_out = data5;
        3'b000: mux_out = data0;
        default: mux_out = 4'b0000;
    endcase
