module nec (
	input clk,rst,
	input ir,
	output reg [7:0]led
	);
wire ir_in;
assign ir_in = ir;
reg [8:0]state_reg, state_next;
reg [31:0]led_reg, led_next;
reg [19:0]count_reg;
wire [19:0]count_next;
reg c_bit_next, c_bit_reg;
reg done_tick;
reg c_load;
wire [7:0]led_tmp;
localparam [8:0]	IDLE		=	9'h001,
					START		=	9'h002,
					SYNC		=	9'h004,
					WAIT_HIGH	=	9'h008,
					FETCH		=	9'h010,
					BCOUNT		=	9'h020,
					WAIT_LOW	=	9'h040,
					CHECK		=	9'h080,
					DONE		=	9'h100;
localparam [19:0]	START_TIME	=	20'd448000,			
					SYNC_TIME	=	20'd210000,			
					CENTER		=	20'd42000;			
reg [1:0]e_bit;	
wire f_edge, r_edge;
always@(posedge clk, negedge rst)
	if(!rst)
		e_bit	<=	2'b00;
	else
		e_bit <= {e_bit[0],ir_in};
assign f_edge = e_bit[1] & (~e_bit[0]);
assign r_edge = (~e_bit[1]) & e_bit[0];
always@(posedge clk, negedge rst)
begin
	if(!rst)
	begin
		state_reg 	<= 		IDLE;
		led_reg		<= 		32'h80000000;
		count_reg	<=		20'h00000;
		c_bit_reg	<=		1'b0;
		led			<=		8'h00;
	end
	else
	begin
		state_reg 	<=		state_next;
		led_reg		<= 		led_next;
		count_reg	<=		count_next;
		c_bit_reg	<=		c_bit_next;
		led			<=		led_tmp;
	end
end
assign count_next = (c_load)?count_reg+1'b1:20'h00000;
always@*
begin
	state_next		=	state_reg;
	led_next		=	led_reg;
	done_tick 		=	1'b0;
	c_load 			=	1'b0;
	c_bit_next		=	c_bit_reg;
	case(state_reg)
		START:
		begin
			c_load = 1'b1;
			if(r_edge)
			begin
				if(count_reg > START_TIME)
				begin
					state_next	=	SYNC;
					c_load = 1'b0;
				end
				else
				begin
					state_next	=	IDLE;
					c_load = 1'b0;
				end	
			end
		end
		SYNC:
		begin
			c_load = 1'b1;
			if(f_edge)
			begin
				if(count_reg > SYNC_TIME)
				begin
					state_next	=	WAIT_HIGH;
					c_load = 1'b0;
				end	
				else
				begin
					state_next	=	IDLE;
					c_load = 1'b0;
				end	
			end
		end
		WAIT_HIGH:
		begin
			if(r_edge)
				state_next	=	FETCH;
		end
		WAIT_LOW:
		begin
			if(f_edge)
				state_next	=	WAIT_HIGH;
		end
		FETCH:
		begin
			c_load = 1'b1;
			if(count_reg > CENTER)
			begin
				c_bit_next	=	led_reg[0];
				led_next 	= 	{ir_in,led_reg[31:1]};
				c_load = 1'b0;
				state_next 	=	BCOUNT;
			end
		end
		BCOUNT:
		begin
			if(c_bit_reg)
				state_next = DONE;
			else
			begin
				if(led_reg[31])
					state_next	=	WAIT_LOW;
				else
					state_next	=	WAIT_HIGH;
			end		
		end
		DONE:
		begin
			if(((led_reg[7:0]^led_reg[15:8]) == 8'hff)&&((led_reg[23:16]^led_reg[31:24]) == 8'hff))
			begin
				done_tick = 1'b1;
				led_next	=	32'h80000000;
				state_next	=	IDLE;
			end	
		end
		IDLE:
		begin
			if(f_edge)
				state_next = START;
		end
	endcase
end
assign led_tmp = (done_tick)?led_reg[23:16]:led;
endmodule

module avr_io_timer
 (	input clk,
	input rst,
	input io_re,
	input io_we,
	input [1:0] io_a,
	output [7:0] io_do,
	input [7:0] io_di,
	output	irq
 );
reg [15:0] TCNT;
reg [7:0]  TTMP;
reg [7:0]  TCR;
reg [11:0]	prescaler;
reg [3:0]	pre_prev;
reg		overflow; 
wire [7:0] TSR = { overflow, 7'b0000000 };
assign irq = TSR[7] & TCR[7];
reg [7:0] io_do_data;
always @(*) begin
	casex (io_a)
		2'b01: io_do_data = TTMP[7:0];
		2'b10: io_do_data = TCR;
		2'b11: io_do_data = TSR;
		2'b00: io_do_data = TCNT[7:0];
        endcase
end
assign io_do = io_re ? io_do_data : 8'b00000000;
always @(posedge clk) begin
	if (io_we & ~io_re) begin
		if ( io_a==2'b01 ) TTMP <= io_di;
		if ( io_a==2'b10 ) TCR  <= io_di;
	end else if ( io_re ) begin
		if ( io_a==2'b00 )
			TTMP <= TCNT[15:8];
	end
end
wire tcnt_write = io_we & (io_a==2'b00);
wire tcr_write  = io_we & (io_a==2'b10);
wire o = overflow & (~tcr_write);
reg increment;
always @(*) begin
	casex (TCR[1:0])
		2'b00: increment = 1;
		2'b01: increment = (~prescaler[ 3])&pre_prev[0];
		2'b10: increment = (~prescaler[ 7])&pre_prev[1];
		2'b11: increment = (~prescaler[11])&pre_prev[2];
	endcase
end
always @(posedge clk) begin
	if ( ! tcnt_write ) begin
		prescaler <= prescaler + 1;
		pre_prev  <= { prescaler[11], prescaler[7], prescaler[3] };
		{ overflow, TCNT } <= { o, 16'd0 } | ( { o, TCNT } + increment );
	end else begin
		TCNT <= { TTMP, io_di };
		prescaler <= 0;
		overflow <= 0;
	end
end
endmodule

module aluout (cry_nxt, data_bus, hcar_nxt, one_nxt, par_nxt, sign_nxt, zero_nxt, adder_c,
               adder_hc, adder_out, hi_byte, logic_c, logic_hc, logic_out, shft_c, shft_out,
               mult_out,
               unit_sel, word_op);
  input         adder_c;       
  input         adder_hc;      
  input         hi_byte;       
  input         logic_c;       
  input         logic_hc;      
  input         shft_c;        
  input         word_op;       
  input   [1:0] unit_sel;      
  input   [7:0] shft_out;      
  input  [15:0] adder_out;     
  input  [15:0] logic_out;     
  input  [15:0] mult_out;      
  output        cry_nxt;       
  output        hcar_nxt;      
  output        one_nxt;       
  output        par_nxt;       
  output        sign_nxt;      
  output        zero_nxt;      
  output [15:0] data_bus;      
  wire        one_nxt, par_nxt, sign_nxt, zero_nxt;
  wire [15:0] data_bus;
  reg         cry_nxt, hcar_nxt;
  reg  [15:0] alu_result;
  always @ (unit_sel or adder_out or logic_out or shft_out or mult_out) begin
    casex (unit_sel)
      2'b10:   alu_result = {8'h00, shft_out};
      2'b11:   alu_result = mult_out;
      2'b01:   alu_result = adder_out;
      default: alu_result = logic_out;
      endcase
    end
  always @ (unit_sel or adder_c or logic_c or shft_c) begin
    casex (unit_sel)
      2'b01:   cry_nxt = adder_c;
      2'b1x:   cry_nxt = shft_c;
      default: cry_nxt = logic_c;
      endcase
    end
  always @ (unit_sel or adder_hc or logic_hc) begin
    casex (unit_sel)
      2'b01:   hcar_nxt = adder_hc;
      2'b1x:   hcar_nxt = 1'b0;
      default: hcar_nxt = logic_hc;
      endcase
    end
  assign one_nxt  = ~|alu_result[7:1] && alu_result[0];
  assign par_nxt  = ~^alu_result[7:0];
  assign sign_nxt = (word_op) ?   alu_result[15]   :   alu_result[7];
  assign zero_nxt = (word_op) ? ~|alu_result[15:0] : ~|alu_result[7:0];
  assign data_bus = (hi_byte) ? {alu_result[7:0], alu_result[7:0]} : alu_result[15:0];
  endmodule

