			2'b10: Y = D[2];
			2'b11: Y = D[3];
			2'b00: Y = D[0];
		endcase
	end

endmodule

module simple_calc(A, B, op, C);
	input [7:0] A;
	input [7:0] B;
	input [1:0] op;
	output reg [7:0] C;

	always @(*)
	begin
		case(op)
			2'b01: C = A - B;
			2'b10: C = A * B;
			2'b11: C = A / B;
			2'b00: C = A + B;
		endcase
	end
endmodule

module mux_2to1 (
    input [1:0] in,
    input sel,
    output reg out
);

    always @(*) begin
        case(sel)
            1: out = in[1];
            0: out = in[0];
        endcase
    end

endmodule
